import{c as n}from"./app.8935f5f1.js";const s={},a=n('<h2 id="iptables防火墙" tabindex="-1"><a class="header-anchor" href="#iptables防火墙" aria-hidden="true">#</a> iptables防火墙</h2><ul><li>有时候关了防火墙，下次登录又开了，发现服务起不来，找半天才发现防火墙又开了，所以建议永久关闭防火墙和selinux</li></ul><ol><li>基本操作</li></ol><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token comment"># 查看防火墙状态</span>\n<span class="token function">service</span> iptables status\n\n<span class="token comment"># 停止防火墙</span>\n<span class="token function">service</span> iptables stop\n\n<span class="token comment"># 启动防火墙</span>\n<span class="token function">service</span> iptables start\n\n<span class="token comment"># 重启防火墙</span>\n<span class="token function">service</span> iptables restart\n\n<span class="token comment"># 永久关闭防火墙</span>\n<span class="token function">chkconfig</span> iptables off\n\n<span class="token comment"># 永久关闭后重启</span>\n<span class="token function">chkconfig</span> iptables on　\n</code></pre></div><ol start="2"><li>开启80端口</li></ol><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token function">vim</span> /etc/sysconfig/iptables\n<span class="token comment"># 加入如下代码</span>\n-A INPUT -m state --state NEW -m tcp -p tcp --dport <span class="token number">80</span> -j ACCEPT\n<span class="token comment"># 保存退出后重启防火墙</span>\n\n<span class="token function">service</span> iptables restart\n\n</code></pre></div><h2 id="firewall防火墙" tabindex="-1"><a class="header-anchor" href="#firewall防火墙" aria-hidden="true">#</a> firewall防火墙</h2><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token comment"># 查看firewall服务状态</span>\n\nsystemctl status firewalld\n\n<span class="token comment"># 查看firewall的状态</span>\n\nfirewall-cmd --state\n\n\n\n<span class="token comment">#### 关闭 firewalld：</span>\n\nsystemctl stop firewalld <span class="token comment">#临时关闭</span>\n\nsystemctl disable firewalld <span class="token comment">#永久关闭,即设置开机的时候不自动启动</span>\n\n\n<span class="token comment"># 开启、重启、关闭、firewalld.service服务</span>\n\n<span class="token comment"># 开启</span>\n<span class="token function">service</span> firewalld start\n<span class="token comment"># 重启</span>\n<span class="token function">service</span> firewalld restart\n<span class="token comment"># 关闭</span>\n<span class="token function">service</span> firewalld stop\n\n\n\n<span class="token comment"># 查看防火墙规则</span>\nfirewall-cmd --list-all\n\n\n</code></pre></div><ol start="2"><li>#查询、开放、关闭端口</li></ol><div class="language-bash ext-sh"><pre class="language-bash"><code>\n<span class="token comment"># 查询端口是否开放</span>\nfirewall-cmd --query-port<span class="token operator">=</span><span class="token number">8080</span>/tcp\n\n<span class="token comment">#开放80端口</span>\nfirewall-cmd --permanent --add-port<span class="token operator">=</span><span class="token number">80</span>/tcp\n<span class="token comment"># 移除端口</span>\nfirewall-cmd --permanent --remove-port<span class="token operator">=</span><span class="token number">8080</span>/tcp\n \n\n<span class="token comment">#重启防火墙(修改配置后要重启防火墙)</span>\nfirewall-cmd --reload\n\n<span class="token comment"># 参数解释</span>\n<span class="token comment"># firwall-cmd：是Linux提供的操作firewall的一个工具；</span>\n<span class="token comment"># --permanent：表示设置为持久；</span>\n<span class="token comment"># --add-port：标识添加的端口；       </span>\n</code></pre></div><h3 id="centos7版本对防火墙进行加强-不再使用原来的iptables-启用firewalld" tabindex="-1"><a class="header-anchor" href="#centos7版本对防火墙进行加强-不再使用原来的iptables-启用firewalld" aria-hidden="true">#</a> centos7版本对防火墙进行加强,不再使用原来的iptables,启用firewalld</h3><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token comment">#1.firewalld的基本使用</span>\n\n<span class="token comment">#启动</span>\n  systemctl start firewalld\n<span class="token comment">#查状态</span>\nsystemctl status firewalld \n<span class="token comment">#停止</span>\n  systemctl disable firewalld\n<span class="token comment">#禁用</span>\n  systemctl stop firewalld\n<span class="token comment">#在开机时启用一个服务</span>\nsystemctl <span class="token builtin class-name">enable</span> firewalld.service\n<span class="token comment">#在开机时禁用一个服务</span>\nsystemctl disable firewalld.service\n<span class="token comment">#查看服务是否开机启动</span>\nsystemctl is-enabled firewalld.service\n<span class="token comment">#查看已启动的服务列表</span>\nsystemctl list-unit-files<span class="token operator">|</span><span class="token function">grep</span> enabled\n<span class="token comment">#查看启动失败的服务列表</span>\nsystemctl --failed\n\n\n<span class="token comment">#2.配置firewalld-cmd</span>\n\n<span class="token comment">#查看版本</span>\n firewall-cmd --version\n<span class="token comment">#查看帮助</span>\n firewall-cmd --help\n<span class="token comment">#显示状态</span>\n firewall-cmd --state\n<span class="token comment">#查看所有打开的端口</span>\n firewall-cmd --zone<span class="token operator">=</span>public --list-ports\n<span class="token comment">#更新防火墙规则</span>\n firewall-cmd --reload\n<span class="token comment">#查看区域信息:  firewall-cmd --get-active-zones</span>\n<span class="token comment">#查看指定接口所属区域</span>\n firewall-cmd --get-zone-of-interface<span class="token operator">=</span>eth0\n<span class="token comment">#拒绝所有包</span>\nfirewall-cmd --panic-on\n<span class="token comment">#取消拒绝状态</span>\n firewall-cmd --panic-off\n<span class="token comment">#查看是否拒绝</span>\n firewall-cmd --query-panic \n</code></pre></div><h4 id="开启一个端口" tabindex="-1"><a class="header-anchor" href="#开启一个端口" aria-hidden="true">#</a> 开启一个端口</h4><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token comment"># 添加</span>\nfirewall-cmd --zone<span class="token operator">=</span>public<span class="token punctuation">(</span>作用域<span class="token punctuation">)</span> --add-port<span class="token operator">=</span><span class="token number">80</span>/tcp<span class="token punctuation">(</span>端口和访问类型<span class="token punctuation">)</span> --permanent<span class="token punctuation">(</span>永久生效<span class="token punctuation">)</span>\nfirewall-cmd --zone<span class="token operator">=</span>public --add-service<span class="token operator">=</span>http --permanent\nfirewall-cmd --reload    <span class="token comment"># 重新载入，更新防火墙规则</span>\nfirewall-cmd --zone<span class="token operator">=</span> public --query-port<span class="token operator">=</span><span class="token number">80</span>/tcp  <span class="token comment">#查看</span>\nfirewall-cmd --zone<span class="token operator">=</span> public --remove-port<span class="token operator">=</span><span class="token number">80</span>/tcp --permanent  <span class="token comment"># 删除</span>\n\nfirewall-cmd --list-services\nfirewall-cmd --get-services\nfirewall-cmd --add-service<span class="token operator">=</span><span class="token operator">&lt;</span>service<span class="token operator">&gt;</span>\nfirewall-cmd --delete-service<span class="token operator">=</span><span class="token operator">&lt;</span>service<span class="token operator">&gt;</span>\n<span class="token comment"># 在每次修改端口和服务后/etc/firewalld/zones/public.xml文件就会被修改,所以也可以在文件中之间修改,然后重新加载</span>\n<span class="token comment"># 使用命令实际也是在修改文件，需要重新加载才能生效。</span>\n\nfirewall-cmd --zone<span class="token operator">=</span>public --query-port<span class="token operator">=</span><span class="token number">80</span>/tcp\nfirewall-cmd --zone<span class="token operator">=</span>public --query-port<span class="token operator">=</span><span class="token number">8080</span>/tcp\nfirewall-cmd --zone<span class="token operator">=</span>public --query-port<span class="token operator">=</span><span class="token number">3306</span>/tcp\nfirewall-cmd --zone<span class="token operator">=</span>public --add-port<span class="token operator">=</span><span class="token number">8080</span>/tcp --permanent\nfirewall-cmd --zone<span class="token operator">=</span>public --add-port<span class="token operator">=</span><span class="token number">3306</span>/tcp --permanent\nfirewall-cmd --zone<span class="token operator">=</span>public --query-port<span class="token operator">=</span><span class="token number">3306</span>/tcp\nfirewall-cmd --zone<span class="token operator">=</span>public --query-port<span class="token operator">=</span><span class="token number">8080</span>/tcp\nfirewall-cmd --reload  <span class="token comment"># 重新加载后才能生效</span>\nfirewall-cmd --zone<span class="token operator">=</span>public --query-port<span class="token operator">=</span><span class="token number">3306</span>/tcp\nfirewall-cmd --zone<span class="token operator">=</span>public --query-port<span class="token operator">=</span><span class="token number">8080</span>/tcp\n</code></pre></div><h4 id="参数解释" tabindex="-1"><a class="header-anchor" href="#参数解释" aria-hidden="true">#</a> 参数解释</h4><div class="language-bash ext-sh"><pre class="language-bash"><code>–add-service <span class="token comment">#添加的服务</span>\n–zone <span class="token comment">#作用域</span>\n–add-port<span class="token operator">=</span><span class="token number">80</span>/tcp <span class="token comment">#添加端口，格式为：端口/通讯协议</span>\n–permanent <span class="token comment">#永久生效，没有此参数重启后失效</span>\n</code></pre></div><h4 id="详细使用" tabindex="-1"><a class="header-anchor" href="#详细使用" aria-hidden="true">#</a> 详细使用</h4><div class="language-bash ext-sh"><pre class="language-bash"><code>firewall-cmd --permanent --zone<span class="token operator">=</span>public --add-rich-rule<span class="token operator">=</span><span class="token string">&#39;rule family=&quot;ipv4&quot; source address=&quot;192.168.0.4/24&quot; service name=&quot;http&quot; accept&#39;</span>    //设置某个ip访问某个服务\nfirewall-cmd --permanent --zone<span class="token operator">=</span>public --remove-rich-rule<span class="token operator">=</span><span class="token string">&#39;rule family=&quot;ipv4&quot; source address=&quot;192.168.0.4/24&quot; service name=&quot;http&quot; accept&#39;</span> //删除配置\nfirewall-cmd --permanent --add-rich-rule <span class="token string">&#39;rule family=ipv4 source address=192.168.0.1/2 port port=80 protocol=tcp accept&#39;</span>     //设置某个ip访问某个端口\nfirewall-cmd --permanent --remove-rich-rule <span class="token string">&#39;rule family=ipv4 source address=192.168.0.1/2 port port=80 protocol=tcp accept&#39;</span>     //删除配置\n\nfirewall-cmd --query-masquerade  <span class="token comment"># 检查是否允许伪装IP</span>\nfirewall-cmd --add-masquerade    <span class="token comment"># 允许防火墙伪装IP</span>\nfirewall-cmd --remove-masquerade <span class="token comment"># 禁止防火墙伪装IP</span>\n\nfirewall-cmd --add-forward-port<span class="token operator">=</span>port<span class="token operator">=</span><span class="token number">80</span>:proto<span class="token operator">=</span>tcp:toport<span class="token operator">=</span><span class="token number">8080</span>   <span class="token comment"># 将80端口的流量转发至8080</span>\nfirewall-cmd --add-forward-port<span class="token operator">=</span>proto<span class="token operator">=</span><span class="token number">80</span>:proto<span class="token operator">=</span>tcp:toaddr<span class="token operator">=</span><span class="token number">192.168</span>.1.0.1 <span class="token comment"># 将80端口的流量转发至192.168.0.1</span>\nfirewall-cmd --add-forward-port<span class="token operator">=</span>proto<span class="token operator">=</span><span class="token number">80</span>:proto<span class="token operator">=</span>tcp:toaddr<span class="token operator">=</span><span class="token number">192.168</span>.0.1:toport<span class="token operator">=</span><span class="token number">8080</span> <span class="token comment"># 将80端口的流量转发至192.168.0.1的8080端口</span>\n \n</code></pre></div><h3 id="centos7以下版本" tabindex="-1"><a class="header-anchor" href="#centos7以下版本" aria-hidden="true">#</a> centos7以下版本</h3><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token comment"># 开放80，22，8080 端口</span>\n/sbin/iptables -I INPUT -p tcp --dport <span class="token number">80</span> -j ACCEPT\n/sbin/iptables -I INPUT -p tcp --dport <span class="token number">22</span> -j ACCEPT\n/sbin/iptables -I INPUT -p tcp --dport <span class="token number">8080</span> -j ACCEPT\n<span class="token comment"># 保存</span>\n/etc/rc.d/init.d/iptables save\n<span class="token comment"># 查看打开的端口</span>\n/etc/init.d/iptables status\n\n<span class="token comment"># 关闭防火墙 </span>\n    <span class="token number">1</span>） 永久性生效，重启后不会复原\n        开启： <span class="token function">chkconfig</span> iptables on\n        关闭： <span class="token function">chkconfig</span> iptables off\n    <span class="token number">2</span>） 即时生效，重启后复原\n        开启： <span class="token function">service</span> iptables start\n        关闭： <span class="token function">service</span> iptables stop \n</code></pre></div>',20);s.render=function(n,s){return a};export{s as default};
